#include "kernel_operator.h"
using namespace AscendC;

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00050Custom {
public:
    __aicore__ inline KernelCa6k00050Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR weight, GM_ADDR bias, GM_ADDR y,
                                uint32_t tileLength, uint32_t blockDim,
                                int32_t strideH, int32_t strideW,
                                int32_t padH, int32_t padW,
                                int32_t dilationH, int32_t dilationW,
                                int32_t kernelH, int32_t kernelW,
                                int32_t inC, int32_t outC,
                                int32_t inH, int32_t inW,
                                int32_t outH, int32_t outW,
                                int32_t batch)
    {
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        strideH_ = strideH;
        strideW_ = strideW;
        padH_ = padH;
        padW_ = padW;
        dilationH_ = dilationH;
        dilationW_ = dilationW;
        kernelH_ = kernelH;
        kernelW_ = kernelW;
        inC_ = inC;
        outC_ = outC;
        inH_ = inH;
        inW_ = inW;
        outH_ = outH;
        outW_ = outW;
        batch_ = batch;
        windowSize_ = inC_ * kernelH_ * kernelW_;

        xGm_.SetGlobalBuffer((__gm__ float*)x);
        wGm_.SetGlobalBuffer((__gm__ float*)weight);
        if (bias != nullptr) {
            hasBias_ = true;
            biasGm_.SetGlobalBuffer((__gm__ float*)bias, outC_);
        } else {
            hasBias_ = false;
        }
        yGm_.SetGlobalBuffer((__gm__ float*)y);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, windowSize_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (outC_ == 0 || outH_ == 0 || outW_ == 0) return;

        uint32_t totalOut = batch_ * outC_ * outH_ * outW_;
        uint32_t myStart = GetBlockIdx() * tileLen_;
        uint32_t myEnd = myStart + tileLen_;
        if (myEnd > totalOut) myEnd = totalOut;

        for (uint32_t idx = myStart; idx < myEnd; idx++) {
            // decode linear index
            uint32_t b = idx / (outC_ * outH_ * outW_);
            uint32_t rem1 = idx % (outC_ * outH_ * outW_);
            uint32_t oc = rem1 / (outH_ * outW_);
            uint32_t rem2 = rem1 % (outH_ * outW_);
            uint32_t oh = rem2 / outW_;
            uint32_t ow = rem2 % outW_;

            // compute convolution
            float sum = 0.0f;
            int32_t hStart = static_cast<int32_t>(oh) * strideH_ - padH_;
            int32_t wStart = static_cast<int32_t>(ow) * strideW_ - padW_;

            for (int32_t ic = 0; ic < inC_; ic++) {
                for (int32_t kh = 0; kh < kernelH_; kh++) {
                    int32_t ih = hStart + kh * dilationH_;
                    if (ih < 0 || ih >= inH_) continue;
                    for (int32_t kw = 0; kw < kernelW_; kw++) {
                        int32_t iw = wStart + kw * dilationW_;
                        if (iw < 0 || iw >= inW_) continue;
                        float x_val = xGm_[((b * inC_ + ic) * inH_ + ih) * inW_ + iw];
                        float w_val = wGm_[((oc * inC_ + ic) * kernelH_ + kh) * kernelW_ + kw];
                        sum += x_val * w_val;
                    }
                }
            }
            if (hasBias_) sum += biasGm_[oc];
            yGm_[idx] = sum;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> biasGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t tileLen_;
    uint32_t blockDim_;
    int32_t strideH_, strideW_, padH_, padW_;
    int32_t dilationH_, dilationW_;
    int32_t kernelH_, kernelW_;
    int32_t inC_, outC_, inH_, inW_, outH_, outW_;
    int32_t batch_, windowSize_;
    bool hasBias_;
};

extern "C" __global__ __aicore__ void ca6k00050_custom(
    GM_ADDR x, GM_ADDR weight, GM_ADDR bias, GM_ADDR y,
    GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00050Custom op;
    op.Init(x, weight, bias, y,
            tiling_data.tileLength, tiling_data.blockDim,
            tiling_data.strideH, tiling_data.strideW,
            tiling_data.padH, tiling_data.padW,
            tiling_data.dilationH, tiling_data.dilationW,
            tiling_data.kernelH, tiling_data.kernelW,
            tiling_data.inC, tiling_data.outC,
            tiling_data.inH, tiling_data.inW,
            tiling_data.outH, tiling_data.outW,
            tiling_data.batch);
    op.Process();
}
